## 1. **Generational Buddy Allocator for WS Buffers**

Jemalloc-style size classes + generations. Perfect for WS (messages cluster around 1KB-64KB).

```javascript
class GenerationalBufferPool {
  // Size classes: 256, 512, 1K, 2K, 4K, 8K, 16K, 32K, 64K
  static SIZE_CLASSES = [256,512,1024,2048,4096,8192,16384,32768,65536];

  constructor() {
    this.#generations = new Map(); // genId → SizeClassPool
    this.#currentGen = 0;
    this.#genSwitchInterval = null;
  }

  get(size) {
    const classIdx = this.#findSizeClass(size);
    const genId = this.#currentGen;

    let pool = this.#generations.get(genId);
    if (!pool) {
      pool = new SizeClassPool(classIdx);
      this.#generations.set(genId, pool);
    }

    return pool.allocate(size);
  }

  release(buffer, requestedSize) {
    const classIdx = this.#findSizeClass(requestedSize);
    const pool = this.#generations.get(this.#currentGen);
    if (pool) pool.release(buffer);
  }

  #findSizeClass(size) {
    return GenerationalBufferPool.SIZE_CLASSES.findIndex(
      cls => cls >= size
    );
  }

  startGenerationSweeps() {
    this.#genSwitchInterval = setInterval(() => {
      this.#promoteAndSweep();
    }, 30000); // 30s generations
  }

  #promoteAndSweep() {
    this.#currentGen++;

    // Sweep OLD gen (2 gens back) → full GC hint
    const oldGen = this.#currentGen - 2;
    const oldPool = this.#generations.get(oldGen);
    if (oldPool) {
      oldPool.sweep(); // release to system
      this.#generations.delete(oldGen);
    }
  }
}

class SizeClassPool {
  constructor(primaryClassIdx) {
    this.#buckets = new Array(GenerationalBufferPool.SIZE_CLASSES.length);
    this.#freeLists = {}; // size → ArrayBuffer[]
    this.#pressure = 0;
  }

  allocate(requestedSize) {
    const classSize = GenerationalBufferPool.SIZE_CLASSES[requestedSize];

    // Fast path: reuse exact size
    if (this.#freeLists[classSize]) {
      const buffer = this.#freeLists[classSize].pop();
      if (buffer) return buffer;
    }

    // Slow path: buddy split
    return new ArrayBuffer(classSize);
  }

  release(buffer) {
    const size = buffer.byteLength;
    if (!this.#freeLists[size]) this.#freeLists[size] = [];
    this.#freeLists[size].push(buffer);

    // Coalesce check (simplified)
    if (this.#freeLists[size].length > 32) {
      this.#freeLists[size] = this.#freeLists[size].slice(-16);
    }
  }
}
```

## 2. **Phantom References + Batch Cleanup Queue**

Custom `PhantomRefQueue` that polls during idle windows:

```javascript
class PhantomRefQueue {
  #pending = new Set();
  #batchTimer = null;
  #pollInterval = null;

  register(obj, cleanupFn) {
    const phantom = new WeakRef(obj);
    const token = { phantom, cleanupFn, timestamp: Date.now() };
    this.#pending.add(token);

    this.#scheduleBatch();
  }

  #scheduleBatch() {
    if (this.#batchTimer) return;

    this.#batchTimer = setTimeout(() => {
      this.#processBatch();
      this.#batchTimer = null;
    }, 100); // 100ms batch window
  }

  #processBatch() {
    const now = Date.now();
    const dead = [];

    for (const token of this.#pending) {
      if (token.phantom.deref() === undefined) {
        dead.push(token);
      } else if (now - token.timestamp > 60000) { // 1min TTL
        dead.push(token);
      }
    }

    dead.forEach(token => {
      token.cleanupFn(token.phantom.deref());
      this.#pending.delete(token);
    });
  }

  // LOW-THROUGHPUT POLLING
  startIdlePolling(throughputMonitor) {
    this.#pollInterval = setInterval(() => {
      if (throughputMonitor.isIdle()) { // <10 msg/s
        this.#processBatch();
      }
    }, 5000);
  }
}
```

**Usage**:
```javascript
const phantomQueue = new PhantomRefQueue();

class ConnectionMetadata {
  constructor(connId) {
    this.connId = connId;
    // Register for auto-cleanup
    phantomQueue.register(this, (metadata) => {
      connectionPool.delete(metadata.connId);
    });
  }
}
```

## 3. **Custom Mark-Sweep for Connection Metadata**

**Complete GC bypass**—manual reference counting + sweep:

```javascript
class MarkSweepConnectionCache {
  #objects = new Map(); // strong refs
  #refCounts = new Map(); // manual RC

  add(key, obj) {
    this.#objects.set(key, obj);
    this.#refCounts.set(key, 1);
  }

  retain(key) { // ++refcount
    const count = this.#refCounts.get(key) || 0;
    this.#refCounts.set(key, count + 1);
  }

  release(key) { // --refcount
    const count = this.#refCounts.get(key);
    if (count > 1) {
      this.#refCounts.set(key, count - 1);
      return;
    }

    // Sweep!
    this.#objects.delete(key);
    this.#refCounts.delete(key);
  }

  // Manual full sweep (call during idle)
  sweep() {
    const dead = [];
    for (const [key, count] of this.#refCounts) {
      if (count === 0) dead.push(key);
    }
    dead.forEach(key => {
      this.#objects.delete(key);
      this.#refCounts.delete(key);
    });
  }
}
```

