## 1. **Lockless Ring Buffer + Atomics (SharedArrayBuffer)**

Zero-contention allocation using CAS on power-of-2 ring:

```javascript
class LocklessBufferRing {
  constructor(capacity = 4096) {
    this.#capacity = capacity;
    this.#mask = capacity - 1;

    // SharedArrayBuffer for Atomics
    this.#ring = new SharedArrayBuffer(capacity * 16); // 16B slots: ptr+size+gen+pad
    this.#slots = new Uint32Array(this.#ring);
    this.#head = 0; // read position
    this.#tail = 0; // write position
    this.#generation = 0;

    Atomics.store(this.#slots, 0, 0); // head
    Atomics.store(this.#slots, 1, 0); // tail  
    Atomics.store(this.#slots, 2, 0); // gen
  }

  // CAS allocate - single atomic instruction
  tryAllocate(size) {
    while (true) {
      const head = Atomics.load(this.#slots, 0);
      const tail = Atomics.load(this.#slots, 1);
      const avail = (head - tail - 1 + this.#capacity) % this.#capacity;

      if (avail < 2) return null; // full

      if (Atomics.compareExchange(this.#slots, 1, tail, tail + 1) === tail) {
        // Won CAS - claim slot
        const slotIdx = tail & this.#mask;
        const bufferAddr = this.#allocateBuffer(size); // your slab

        // Write slot atomically: [ptr_hi, ptr_lo, size, gen]
        Atomics.store(this.#slots, slotIdx * 4 + 0, bufferAddr >>> 32);
        Atomics.store(this.#slots, slotIdx * 4 + 1, bufferAddr & 0xFFFFFFFF);
        Atomics.store(this.#slots, slotIdx * 4 + 2, size);
        Atomics.store(this.#slots, slotIdx * 4 + 3, this.#generation);

        return bufferAddr;
      }
    }
  }

  // Consumer dequeues
  dequeue() {
    const tail = Atomics.load(this.#slots, 1);
    const head = Atomics.load(this.#slots, 0);

    if (head === tail) return null;

    const slotIdx = head & this.#mask;
    const ptrHi = Atomics.load(this.#slots, slotIdx * 4 + 0);
    const ptrLo = Atomics.load(this.#slots, slotIdx * 4 + 1);
    const size = Atomics.load(this.#slots, slotIdx * 4 + 2);

    // Advance head
    Atomics.store(this.#slots, 0, head + 1);

    return { ptr: (ptrHi << 32) | ptrLo, size };
  }
}
```

## 2. **Hazard Pointers for Safe Reclamation**

**Memory reclamation without GC**—producers publish, consumers claim with hazard pointers:

```javascript
class HazardPointers {
  static MAX_THREADS = 64; // workers/isolates
  static HP_PER_THREAD = 2; // read/write hazards

  constructor() {
    this.#hazardSlots = new SharedArrayBuffer(MAX_THREADS * HP_PER_THREAD * 8);
    this.#hazards = new BigUint64Array(this.#hazardSlots);
    this.#retiredList = new Set();
  }

  // Producer: publish pointer
  publish(ptr) {
    this.#retiredList.add(ptr);
    this.#scanAndReclaim();
  }

  // Consumer: protect pointer from reclamation
  protect(ptr, hazardIdx = 0) {
    const threadId = this.#getThreadId(); // worker id
    Atomics.store(
      this.#hazards, 
      threadId * HazardPointers.HP_PER_THREAD + hazardIdx, 
      BigInt(ptr)
    );
  }

  #scanAndReclaim() {
    const hazards = [];

    // Collect all hazard pointers
    for (let i = 0; i < HazardPointers.MAX_THREADS; i++) {
      hazards.push(Number(this.#hazards[i * 2]));
      hazards.push(Number(this.#hazards[i * 2 + 1]));
    }

    // Reclaim anything NOT in hazard list
    for (const ptr of this.#retiredList) {
      if (!hazards.includes(ptr)) {
        this.#freeBuffer(ptr);
        this.#retiredList.delete(ptr);
      }
    }
  }
